import { getCurrentPageData } from "../api/data";

const DATA_LIMIT = 20;

const types = {
  setCurrentPage: "setCurrentPage",
  setData: "setData",
};

export const initialData = {
  currentPageData: new Array(DATA_LIMIT).fill(0),
  currentPage: 1,
  data: [],
};

export const reducerData = (state, action) => {
  switch (action.type) {
    case types.setData:
      return {
        ...state,
        data: action.payload,
        currentPageData: getCurrentPageData(action.payload, state.currentPage),
      };
    case types.setCurrentPage:
      return {
        ...state,
        currentPage: action.payload,
        currentPageData: getCurrentPageData(state.data, action.payload),
      };
  }
};

export const actionData = {
  setData: (arr) => ({ type: types.setData, payload: arr }),
  setCurrentPage: (num) => ({ type: types.setCurrentPage, payload: num }),
};
