import React from "react";
import { readBookTitlesAsync } from "../api/firebase";
import { actionData, initialData, reducerData } from "../reducers/data";

const contextBooks = React.createContext();

export default function useBooks() {
  return React.useContext(contextBooks);
}

export function BookContextProvider({ children }) {
  const [state, dispatch] = React.useReducer(reducerData, initialData);

  const downloadData = React.useCallback(async () => {
    const data = await readBookTitlesAsync();
    dispatch(actionData.setData(data));
  }, []);

  React.useEffect(() => {
    downloadData();
  }, []);

  // Methods
  const setIndex = React.useCallback((id) => {
    dispatch(actionData.setCurrentPage(id));
  }, []);

  const value = { data: state.data, state, setIndex };

  return (
    <contextBooks.Provider value={value}>{children}</contextBooks.Provider>
  );
}
