import { createDrawerNavigator } from "@react-navigation/drawer";
import React from "react";
import TitleList from "~/common/components/major/TitlesList";
import ZawgyiUnicodeConverter from "~/common/components/minor/ZawgyiUnicodeConverter";
import { Home } from "~/common/screens";

const Drawer = createDrawerNavigator();
const LazyDrawerContent = React.lazy(() =>
  import("../../components/major/TitlesList")
);

export const DrawerContent = () => (
  <React.Suspense fallback={<View style={{ flex: 1 }} />}>
    <LazyDrawerContent />
  </React.Suspense>
);

export default function DrawerNavigator() {
  return (
    <Drawer.Navigator
      drawerContent={() => <DrawerContent />}
      screenOptions={{
        headerRight: () => <ZawgyiUnicodeConverter />,
        headerTintColor: "white",
      }}
    >
      <Drawer.Screen name="Home" component={Home} />
    </Drawer.Navigator>
  );
}
