import useSettings from "~/utils/hooks/useSettings";

export default function ZawgyiUnicodeConverter() {
  const { font, changeFont } = useSettings();

  return (
    <button
      type="button"
      className={"btn btn-outline-success text-capitalize me-2"}
      title={"zawgy unicode converter"}
      onClick={changeFont}
    >
      {font}
    </button>
  );
}
